  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭 ID',
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '閭??鍦板潃',
  `purpose` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鐢ㄩ?锛歳egister-娉ㄥ唽锛宭ogin-鐧诲綍锛宺eset-瀵嗙爜閲嶇疆锛寁erify-閭??楠岃瘉锛宑hange-閭??淇?敼',
  `action` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鎿嶄綔锛歴end-鍙戦?锛寁erify-楠岃瘉锛宖ail-澶辫触',
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'IP 鍦板潃',
  `user_agent` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鐢ㄦ埛浠ｇ悊',
  `success` tinyint NOT NULL DEFAULT '0' COMMENT '鏄?惁鎴愬姛锛?-澶辫触锛?-鎴愬姛',
  `error_message` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '閿欒?淇℃伅',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  PRIMARY KEY (`id`),
  KEY `idx_email` (`email`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_ip_address` (`ip_address`)
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='閭?欢楠岃瘉鏃ュ織琛';
