UNLOCK TABLES;
DROP TABLE IF EXISTS `t_tool_review`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_tool_review` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '评论 ID',
  `tool_id` bigint NOT NULL COMMENT '工具 ID',
  `user_id` bigint NOT NULL COMMENT '用户 ID',
  `rating` tinyint NOT NULL COMMENT '评分: 1-5 星',
  `title` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '评论标题',
  `content` text COLLATE utf8mb4_unicode_ci COMMENT '评论内容',
  `helpful_count` int NOT NULL DEFAULT '0' COMMENT '有帮助的点赞数',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '审核状态: 0-待审核, 1-已通过, 2-已拒绝',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_tool_id` (`tool_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_rating` (`rating`),
  KEY `idx_helpful` (`helpful_count` DESC)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='工具评论表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `t_tool_review` WRITE;
/*!40000 ALTER TABLE `t_tool_review` DISABLE KEYS */;
/*!40000 ALTER TABLE `t_tool_review` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `t_tool_tag`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_tool_tag` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '关联 ID',
  `tool_id` bigint NOT NULL COMMENT '工具 ID',
  `tag_id` bigint NOT NULL COMMENT '标签 ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tool_tag` (`tool_id`,`tag_id`),
  KEY `idx_tool_id` (`tool_id`),
  KEY `idx_tag_id` (`tag_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='工具标签关联表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `t_tool_tag` WRITE;
/*!40000 ALTER TABLE `t_tool_tag` DISABLE KEYS */;
/*!40000 ALTER TABLE `t_tool_tag` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `t_tool_usage`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_tool_usage` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录 ID',
  `user_id` bigint NOT NULL COMMENT '用户 ID, 0 表示匿名用户',
  `tool_id` bigint NOT NULL COMMENT '工具 ID',
  `used_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '使用时间',
  `duration` int DEFAULT NULL COMMENT '使用时长（秒）',
  `ip_address` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'IP 地址',
  `user_agent` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'User-Agent',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '删除标记:0-正常,1-已删除',
  PRIMARY KEY (`id`),
  KEY `idx_user_time` (`user_id`,`used_at` DESC),
  KEY `idx_tool_time` (`tool_id`,`used_at` DESC),
  KEY `idx_used_at` (`used_at` DESC),
  KEY `idx_deleted` (`deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=96 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='工具使用记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `t_tool_usage` WRITE;
/*!40000 ALTER TABLE `t_tool_usage` DISABLE KEYS */;
