UNLOCK TABLES;
DROP TABLE IF EXISTS `t_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_user` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户 ID',
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户名',
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'BCrypt 加密密码',
  `password_updated_at` datetime DEFAULT NULL COMMENT '密码最后修改时间',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '邮箱',
  `nickname` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '昵称',
  `avatar` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像 URL',
  `avatar_config` text COLLATE utf8mb4_unicode_ci COMMENT '头像自定义配置(JSON)',
  `bio` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '个人简介',
  `language` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT 'zh-CN' COMMENT '用户语言偏好: zh-CN(简体中文), en-US(英语)',
  `plan_type` smallint NOT NULL DEFAULT '0' COMMENT '会员类型: 0-Free, 1-Pro, 2-Enterprise, 999-Admin',
  `plan_expired_at` datetime DEFAULT NULL COMMENT '会员到期时间',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态: 0-禁用, 1-正常',
  `last_login_at` datetime DEFAULT NULL COMMENT '最后登录时间',
  `last_login_ip` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最后登录 IP',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除: 0-未删除, 1-已删除',
  `email_verified` tinyint(1) DEFAULT '0' COMMENT '邮箱是否已验证: 0-未验证, 1-已验证',
  `email_verified_at` datetime DEFAULT NULL COMMENT '邮箱验证时间',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '手机号',
  `phone_verified` tinyint(1) DEFAULT '0' COMMENT '手机号是否已验证: 0-未验证, 1-已验证',
  `phone_verified_at` datetime DEFAULT NULL COMMENT '手机号验证时间',
