/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `verification_alert_history` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `alert_type` varchar(50) NOT NULL COMMENT '鍛婅?绫诲瀷: SEND_FAILURE_RATE/VERIFY_FAILURE_RATE/RATE_LIMIT_TRIGGERS/ANOMALY_DETECTION',
  `title` varchar(200) NOT NULL COMMENT '鍛婅?鏍囬?',
  `message` text COMMENT '鍛婅?娑堟伅',
  `level` varchar(20) NOT NULL COMMENT '鍛婅?绾у埆: INFO/WARNING/CRITICAL',
  `alert_time` datetime NOT NULL COMMENT '鍛婅?鏃堕棿',
  `resolved` tinyint DEFAULT '0' COMMENT '鏄?惁宸插?鐞? 0-鏈??鐞? 1-宸插?鐞',
  `resolved_time` datetime DEFAULT NULL COMMENT '澶勭悊鏃堕棿',
  `resolved_by` varchar(100) DEFAULT NULL COMMENT '澶勭悊浜',
  `resolve_note` varchar(500) DEFAULT NULL COMMENT '澶勭悊澶囨敞',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  `deleted` tinyint DEFAULT '0' COMMENT '杞?垹闄ゆ爣璁? 0-鏈?垹闄? 1-宸插垹闄',
  PRIMARY KEY (`id`),
  KEY `idx_alert_type` (`alert_type`),
  KEY `idx_alert_time` (`alert_time`),
  KEY `idx_level` (`level`),
  KEY `idx_resolved` (`resolved`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='楠岃瘉鐮佸憡璀﹀巻鍙茶〃';
